1	const fs = require('fs');
2	const path = require('path');
3	
4	const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
5	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
6	const NOW = Date.now();
7	const DAY = 86400000;
8	const OUR_UID = '2500000853693@icbu';
9	
10	// ── 工具函数 ──
11	const SYS_PATTERNS = [
12	  '自动接待将不再触发', 'Since you have read the conversation',
13	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
14	  '买家有流失风险', 'Buyer has churn risk',
15	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
16	  '反馈', 'AI给您生成了一条回复建议',
17	  'You have a visitor', 'This buyer has been pre-screened',
18	  '当前买家首次给您发消息', 'AI给您生成',
19	];
20	function isSys(c) { const t = c && c.text && c.text.content || ''; if (!t.trim()) return true; for (const p of SYS_PATTERNS) if (t.includes(p)) return true; return false; }
21	function getText(c) { return c && c.text && c.text.content || ''; }
22	
23	const Q_PATTERNS = [/\?/, /(what|how|when|where|which|who|why|whom)/i, /(can you|could you|would you|will you|do you|is it|are you)/i, /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know))/i, /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i, /[吗呢吧啊]/, /[？]/, /(价格|报价|多少钱|什么价)/, /(样品|sample|打样)/i, /(MOQ|起订量|最小.*量)/i, /(交期|delivery.*time|lead.*time)/i];
24	function isQuestion(text) { if (!text || text.length < 3) return false; for (const p of Q_PATTERNS) if (p.test(text)) return true; return false; }
25	
26	function assessQuality(qText, rText) {
27	  if (!rText || rText.trim().length === 0) return { q: '未回复', s: 0 };
28	  const len = rText.trim().length;
29	  if (/^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i.test(rText.trim()) || len < 15) return { q: '敷衍回复', s: 1 };
30	  if (len < 50) return { q: '简短回复', s: 2 };
31	  const qw = (qText || '').toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
32	  const rl = rText.toLowerCase();
33	  const m = qw.filter(w => rl.includes(w));
34	  return (m.length / Math.max(qw.length, 1) >= 0.3 || len >= 100) ? { q: '充分回复', s: 3 } : { q: '简短回复', s: 2 };
35	}
36	
37	// ── 生命周期判定 ──
38	function determineLifecycle(e) {
39	  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
40	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
41	
42	  // 售后：质量问题/投诉
43	  if (/(problem|issue|damage|broken|wrong|defect|complain|refund|return|bad quality|poor quality|not good|有问题|坏的|退货|退款|投诉)/i.test(fullText)) return { stage: 8, label: '售后', icon: '🔧' };
44	
45	  // 订单执行中：付款确认+生产/发货讨论
46	  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };
47	
48	  // 已签收
49	  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };
50	
51	  // PI已发（不限天数，只看信号）
52	  if (hasPI) return { stage: 5, label: 'PI已发', icon: '📄' };
53	
54	  // 谈判/样品（不限天数）
55	  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10) return { stage: 4, label: '谈判/样品', icon: '🤝' };
56	  if (hasSample && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };
57	
58	  // 报价已发（不限天数）
59	  if (hasPrice) return { stage: 3, label: '报价已发', icon: '💰' };
60	
61	  // 待回复：客户有新消息未回
62	  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };
63	
64	  // 初询沟通（不限天数）
65	  if (realMsgs >= 1) return { stage: 2, label: '初询沟通', icon: '📋' };
66	
67	  return { stage: 0, label: '待分类', icon: '❓' };
68	}
69	
70	// ── 沉默副状态 ──
71	function silenceLabel(days) {
72	  if (days >= 90) return '沉淀(90d+)';
73	  if (days >= 30) return '深度沉默(30-90d)';
74	  if (days >= 14) return '长期沉默(14-30d)';
75	  if (days >= 7) return '中期沉默(7-14d)';
76	  if (days >= 3) return '短期沉默(3-7d)';
77	  return '';
78	}
79	
80	// ── 质量等级判定 ──
81	function determineQuality(e, fullCustText, fullConvText) {
82	  const ft = (fullConvText || '').toLowerCase();
83	  const ct = (fullCustText || '').toLowerCase();
84	
85	  // ── 全量对话提取数量信息（从客户消息提取更可靠）──
86	  // 支持英/中/法/西/阿语常见数量单位
87	  const qtyMatches = ct.match(/(\d{3,})\s*(pcs|pieces|units?|unit[ée]s?|件|piece|pc|pce|paires?|douzaines?|qt[ée]|quantit[ée]s?|sets?|ensembles?)/gi) || [];
88	  let maxQty = 0;
89	  for (const qm of qtyMatches) {
90	    const n = parseInt(qm.match(/\d+/)[0], 10);
91	    if (n > maxQty) maxQty = n;
92	  }
93	
94	  // ── 母婴品类信号（修正 D 误判用）──
95	  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);
96	
97	  // ── S 级信号（严格版 — 优先用 ct 即客户消息）──
98	  const sSignals = [];
99	  // 品牌/ODM: 明确且有意图的组合（含法/西/阿语）
100	  if (/(odm|oem|private\s*(label|brand)|own\s*(brand|design|label)|custom\s*(logo|packaging|packing|design|label|box|bag|tag)|hangtag|barcode|brand\s*name|brand\s*label|your\s*logo|my\s*logo|our\s*logo|marque|personnalis[ée]|personnaliser|[ée]tiquette.*perso|logo.*perso|votre.*logo|mon.*logo|mon.*design|mon.*propre)/i.test(ct))
101	    sSignals.push('品牌/ODM');
102	  // 分销渠道: 明确平台或分销语言（含法/西/阿语）
103	  if (/(amazon|walmart|shopify|distributor|retail\s*(chain|store|shop)|wholesale\s*(channel|distributor|business)|sell\s*(on|through|in)\s*(amazon|walmart|shopify|online)|revendeur|distributeur|vendre.*(sur|en ligne|amazon)|boutique.*(en ligne|online)|tienda.*(online|en.linea)|mayorista)/i.test(ct))
104	    sSignals.push('分销渠道');
105	  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
106	  // 公司资料: 客户主动分享
107	  if (/(here.*(is|are).*(website|store|shop|link)|check.*(my|our).*(website|store|shop|page)|this\s*is\s*(my|our).*(website|store|shop)|find\s*(us|me).*(on|at).*(website|store))/i.test(ct) ||
108	      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
109	    sSignals.push('公司资料');
110	  // 复购: 明确的复购/追加语言
111	  if (/(reorder|restock|another\s*(order|shipment|batch|container)|second\s*(order|shipment)|repeat\s*order|buy\s*more|order\s*more|send\s*more|top\s*up)/i.test(ct))
112	    sSignals.push('复购信号');
113	
114	  // ── A 级附加信号 ──
115	  const aSignals = [];
116	  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
117	  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq)|(je|nous).*(prends?|commande|veux|voudrais).*500|500.*(va|marche|ok|d'accord)|pas.*probl[èe]me.*500)/i.test(ct))
118	    aSignals.push('MOQ已接受');
119	  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
120	    aSignals.push('样品已寄/在准备');
121	  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
122	    aSignals.push('深度沟通(' + e.realMsgs + '条)');
123	  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点|r[ée]duction|remise|rabais|n[ée]goci|trop.*(cher|[ée]lev[ée]|haut)|moins.*cher|prix.*(bas|moins)|descuento|rebaja|caro|muy.*caro|barato)/i.test(ct))
124	    aSignals.push('价格谈判');
125	  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ct))
126	    aSignals.push('关心认证/验厂');
127	  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ct) && e.hasQuantity)
128	    aSignals.push('讨论运费+数量');
129	
130	  // ── C 级降级信号 ──
131	  const cSignals = [];
132	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use|just.*for.*(me|myself|my.*kid|my.*baby)|pour moi|pour mon|personnel|usage.*personnel|uso.*personal|para mi)/i.test(ct))
133	    cSignals.push('个人自用');
134	  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces)|petit.*(quantit[ée]|commande)|peu.*(de|commande)|juste.*(quelques|un peu)|solo.*(pocos?|pocas?|unos?|unas?))/i.test(ct))
135	    cSignals.push('小批量暗示');
136	  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
137	  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample && !e.hasQuantity)
138	    cSignals.push('单次浅层互动');
139	
140	  // ── D 级判定（修正版）──
141	  if (e.realMsgs <= 2 && e.customerMsgs === 0)
142	    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
143	
144	  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
145	  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
146	    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };
147	
148	  // 非采购意图
149	  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
150	    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };
151	
152	  // ── 综合定级 ──
153	  const totalSSignals = sSignals.length;
154	  const totalASignals = aSignals.length;
155	  const totalCSignals = cSignals.length;
156	
157	  // S: 2+ 个S级信号
158	  if (totalSSignals >= 2)
159	    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
160	
161	  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
162	  if (totalSSignals >= 1)
163	    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };
164	
165	  if (totalASignals >= 2 && e.realMsgs >= 5)
166	    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };
167	
168	  // C: 明确降级信号 + 无上升信号
169	  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
170	    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };
171	
172	  if (maxQty > 0 && maxQty <= 30 && totalSSignals === 0 && totalASignals === 0)
173	    return { grade: 'C', label: '低价值', reason: '明确小量≤30件', auto: true };
174	
175	  // 单次互动无后续 → C（而非B）
176	  if (e.realMsgs <= 4 && e.customerMsgs >= 1 && e.customerMsgs <= 2 && !e.hasPrice && !e.hasSample && !e.hasQuantity && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 30)
177	    return { grade: 'C', label: '低价值', reason: '单次互动+30天无后续', auto: true };
178	
179	  // 浅互动+长期沉默 → C（"问完消失"模式）
180	  if (e.realMsgs <= 5 && e.customerMsgs <= 2 && totalSSignals === 0 && totalASignals <= 1 && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 60)
181	    return { grade: 'C', label: '低价值', reason: '浅互动+长期沉默(' + e.lastCustomerMsgDays + 'd)', auto: true };
182	
183	  // B: 有实质互动，信号不足以升A/S也不足以降C/D
184	  if (e.realMsgs >= 3 && e.customerMsgs >= 1)
185	    return { grade: 'B', label: '普通客户', reason: '有互动但信号不足', auto: true };
186	
187	  if (e.hasPrice || e.hasSample || e.hasQuantity)
188	    return { grade: 'B', label: '普通客户', reason: '有实质讨论', auto: true };
189	
190	  return { grade: 'B', label: '普通客户', reason: '信息不足', auto: true };
191	}
192	
193	// ── 主循环 ──
194	const allResults = [];
195	for (let i = 0; i <= 4; i++) { if (s1.results[i]) allResults.push(...s1.results[i]); }
196	const candidates = allResults;
197	console.log('处理全部 ' + candidates.length + ' 个客户 (P0-P4)...\n');
198	
199	const enhanced = [];
200	for (const c of candidates) {
201	  const fid = c.cid ? c.cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
202	  const fp = path.join(chatDir, fid);
203	
204	  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
205	  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
206	  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
207	  let latestOurMsg = '', latestOurDate = '', latestCustMsg = '', latestCustDate = '';
208	  let lastCustomerMsgDays = 9999;
209	  let lastCustQuestion = '', lastCustQuestionDate = '', ourResponseQuality = 'N/A';
210	  let responseGapDays = -1, questionUnanswered = false;
211	  let fullCustText = '', fullConvText = '';
212	
213	  if (fs.existsSync(fp)) {
214	    try {
215	      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
216	      const msgs = data.messages || [];
217	      msgCount = msgs.length;
218	
219	      for (const m of msgs) {
220	        const msg = m.message || m;
221	        const uid = msg.sender && msg.sender.uid || '';
222	        const text = getText(msg.content);
223	        const date = msg.createAt || '';
224	        if (isSys(msg.content)) { sysMsgs++; continue; }
225	
226	        if (uid === OUR_UID) {
227	          ourMsgs++; if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
228	          if (text.trim()) fullConvText += '[我方] ' + text + ' | ';
229	        } else if (uid) {
230	          customerMsgs++;
231	          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
232	          if (text.trim()) { fullCustText += text + ' | '; fullConvText += '[客户] ' + text + ' | '; }
233	          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
234	        }
235	
236	        const lc = text.toLowerCase();
237	        if (/pi|proforma\s*invoice|invoice\s*sent|付款|deposit|定金|tt\s|wire\s*transfer|bank\s*transfer/.test(lc + text)) hasPI = true;
238	        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
239	        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
240	        if (/(price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
241	        if (/(sample|样品)/.test(lc)) hasSample = true;
242	        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
243	        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
244	        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
245	      }
246	
247	      // 找最后的客户提问
248	      const sortedMsgs = [...msgs].filter(m => !isSys((m.message || m).content)).sort((a, b) => ((b.message || b).createAt || 0) - ((a.message || a).createAt || 0));
249	      for (const m of sortedMsgs) {
250	        const msg = m.message || m;
251	        const uid = msg.sender && msg.sender.uid || '';
252	        const text = getText(msg.content);
253	        if (uid && uid !== OUR_UID && isQuestion(text)) { lastCustQuestion = text; lastCustQuestionDate = msg.createAt || ''; break; }
254	      }
255	
256	      if (lastCustQuestion && lastCustQuestionDate) {
257	        const qTs = new Date(lastCustQuestionDate).getTime();
258	        let respText = '', respDate = '';
259	        for (const m of [...sortedMsgs].reverse()) {
260	          const msg = m.message || m;
261	          const ts = (msg.createAt || 0);
262	          if ((msg.sender && msg.sender.uid) === OUR_UID && ts > qTs) { respText = getText(msg.content); respDate = msg.createAt || ''; break; }
263	        }
264	        if (respText) {
265	          const gapH = (new Date(respDate).getTime() - qTs) / 3600000;
266	          responseGapDays = Math.round(gapH / 24 * 10) / 10;
267	          const a = assessQuality(lastCustQuestion, respText);
268	          ourResponseQuality = a.q + ' (' + responseGapDays + 'd)';
269	        } else {
270	          ourResponseQuality = '未回复';
271	          responseGapDays = Math.round((NOW - qTs) / DAY * 10) / 10;
272	          questionUnanswered = true;
273	        }
274	      }
275	    } catch (e) { /* skip corrupt */ }
276	  }
277	
278	  const realMsgs = customerMsgs + ourMsgs;
279	  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;
280	  const country = c.country || '';
281	  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
282	  const isCore = coreMarkets.includes(country);
283	
284	  const obj = {
285	    name: c.name || '(未知)', country, isCore, daysAgo: c.daysAgo,
286	    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
287	    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
288	    latestOurMsg: latestOurMsg.substring(0, 100), latestCustMsg: latestCustMsg.substring(0, 100),
289	    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
290	    lastCustQuestion: lastCustQuestion.substring(0, 200), ourResponseQuality, responseGapDays, questionUnanswered,
291	    cid: c.cid, filename: fid,
292	  };
293	
294	  // 双轴分类
295	  const lc = determineLifecycle(obj);
296	  const ql = determineQuality(obj, fullCustText, fullConvText);
297	  const sil = silenceLabel(obj.lastCustomerMsgDays === '-' ? 999 : obj.lastCustomerMsgDays);
298	
299	  obj.stage = lc.stage;
300	  obj.stageLabel = lc.label;
301	  obj.stageIcon = lc.icon;
302	  obj.grade = ql.grade;
303	  obj.gradeLabel = ql.label;
304	  obj.gradeReason = ql.reason;
305	  obj.gradeAuto = ql.auto;
306	  obj.silenceState = sil;
307	
308	  // 行动信号
309	  const signals = [];
310	  if (questionUnanswered) signals.push('提问未回复');
311	  if (ourResponseQuality.startsWith('敷衍回复') && obj.daysAgo < 3) signals.push('敷衍回复需补救');
312	  if (responseGapDays > 3 && questionUnanswered) signals.push('超3天未回');
313	  if (ql.grade === 'S' || ql.grade === 'A') signals.push(ql.grade + '级客户');
